import argparse
import json
from pathlib import Path

import torch
import torch.nn as nn
import torch.nn.functional as F
from PIL import Image, ImageFile
from torch.utils.data import Dataset, DataLoader
from torchvision import transforms
from transformers import CLIPModel

ImageFile.LOAD_TRUNCATED_IMAGES = True

NUM_CLASSES = 182
CLIP_MEAN = (0.48145466, 0.4578275, 0.40821073)
CLIP_STD = (0.26862954, 0.26130258, 0.27577711)


class FeatureHead(nn.Module):
    def __init__(self, dim, num_classes=NUM_CLASSES, dropout=0.0, hidden_dim=0):
        super().__init__()
        if hidden_dim and hidden_dim > 0:
            self.net = nn.Sequential(
                nn.LayerNorm(dim),
                nn.Dropout(dropout),
                nn.Linear(dim, hidden_dim),
                nn.GELU(),
                nn.Dropout(dropout),
                nn.Linear(hidden_dim, num_classes),
            )
        else:
            self.net = nn.Sequential(
                nn.LayerNorm(dim),
                nn.Dropout(dropout),
                nn.Linear(dim, num_classes),
            )

    def forward(self, x):
        return self.net(x.float())


def strip_module(sd):
    return {k[7:] if k.startswith('module.') else k: v for k, v in sd.items()}


def find_feature_state(ckpt):
    if not isinstance(ckpt, dict):
        raise RuntimeError('checkpoint is not a dict')
    for key in [
        'feature_head_state_dict',
        'classifier_state_dict',
        'feature_head_state',
        'feature_head',
        'head_state_dict',
        'head',
        'model_state_dict',
        'state_dict',
    ]:
        obj = ckpt.get(key)
        if isinstance(obj, dict):
            sd = strip_module(obj)
            if any(k.startswith('net.') for k in sd.keys()):
                return sd
    raise RuntimeError('No feature-head state_dict found')


def infer_dims(sd, ckpt):
    dim = int(ckpt.get('feature_dim', 0) or 0) if isinstance(ckpt, dict) else 0
    hidden = int(ckpt.get('hidden_dim', 0) or 0) if isinstance(ckpt, dict) else 0
    if 'net.5.weight' in sd:
        hidden = int(sd['net.5.weight'].shape[1])
        if dim <= 0 and 'net.2.weight' in sd:
            dim = int(sd['net.2.weight'].shape[1])
    elif 'net.2.weight' in sd:
        hidden = 0
        if dim <= 0:
            dim = int(sd['net.2.weight'].shape[1])
    if dim <= 0:
        for v in sd.values():
            if torch.is_tensor(v) and v.ndim == 2:
                dim = int(v.shape[1])
                break
    if dim <= 0:
        raise RuntimeError('Could not infer feature dimension')
    return dim, hidden


def coerce_clip_output_to_tensor(out, clip_model):
    if torch.is_tensor(out):
        return out
    if hasattr(out, 'image_embeds') and torch.is_tensor(out.image_embeds):
        return out.image_embeds
    if hasattr(out, 'pooler_output') and torch.is_tensor(out.pooler_output):
        val = out.pooler_output
        proj = getattr(clip_model, 'visual_projection', None)
        if proj is not None and hasattr(proj, 'in_features') and val.shape[-1] == proj.in_features:
            return proj(val)
        return val
    if hasattr(out, 'last_hidden_state') and torch.is_tensor(out.last_hidden_state):
        val = out.last_hidden_state[:, 0]
        proj = getattr(clip_model, 'visual_projection', None)
        if proj is not None and hasattr(proj, 'in_features') and val.shape[-1] == proj.in_features:
            return proj(val)
        return val
    raise RuntimeError('Could not coerce CLIP image output')


class ImageDataset(Dataset):
    def __init__(self, data_path, image_size=224):
        self.data_path = Path(data_path)
        self.image_dir = self.data_path / 'images'
        with open(self.data_path / 'test.txt', 'r') as f:
            self.names = [line.strip().split()[0] for line in f if line.strip()]
        self.transform = transforms.Compose([
            transforms.Resize((image_size, image_size), interpolation=transforms.InterpolationMode.BICUBIC),
            transforms.ToTensor(),
            transforms.Normalize(CLIP_MEAN, CLIP_STD),
        ])

    def __len__(self):
        return len(self.names)

    def __getitem__(self, idx):
        name = self.names[idx]
        path = self.image_dir / name
        try:
            im = Image.open(path).convert('RGB')
        except Exception:
            im = Image.new('RGB', (224, 224), (0, 0, 0))
        return self.transform(im)


@torch.no_grad()
def extract_features(clip_model, pixel_values):
    try:
        out = clip_model.get_image_features(pixel_values=pixel_values)
    except Exception:
        out = clip_model.vision_model(pixel_values=pixel_values)
    feats = coerce_clip_output_to_tensor(out, clip_model).float()
    return F.normalize(feats, dim=-1)


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True)
    parser.add_argument('--checkpoint', required=True)
    parser.add_argument('--output', required=True)
    parser.add_argument('--batch_size', type=int, default=256)
    parser.add_argument('--num_workers', type=int, default=8)
    args = parser.parse_args()

    device = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
    ckpt = torch.load(args.checkpoint, map_location='cpu')

    model_name = ckpt.get('clip_model_name', ckpt.get('model_name', 'openai/clip-vit-base-patch16'))
    if isinstance(model_name, str):
        model_name = model_name.replace('_', '/') if model_name.startswith('openai_clip') else model_name
    else:
        model_name = 'openai/clip-vit-base-patch16'
    if 'large' not in model_name and 'base' not in model_name:
        model_name = 'openai/clip-vit-base-patch16'

    sd = find_feature_state(ckpt)
    dim, hidden = infer_dims(sd, ckpt)
    dropout = float(ckpt.get('dropout', 0.0) or 0.0)
    head = FeatureHead(dim, NUM_CLASSES, dropout=dropout, hidden_dim=hidden)
    head.load_state_dict(sd, strict=True)
    head.to(device).eval()

    clip_model = CLIPModel.from_pretrained(model_name).to(device).eval()

    image_size = int(ckpt.get('image_size', 224) or 224)
    ds = ImageDataset(args.data_path, image_size=image_size)
    dl = DataLoader(
        ds,
        batch_size=args.batch_size,
        shuffle=False,
        num_workers=args.num_workers,
        pin_memory=torch.cuda.is_available(),
    )

    logp = None
    tau = float(ckpt.get('bias_tau', 0.0) or 0.0)
    counts = ckpt.get('train_class_counts', None)
    if counts is not None:
        counts = torch.as_tensor(counts, dtype=torch.float32, device=device)
        if counts.numel() == NUM_CLASSES:
            logp = torch.log((counts + 1.0) / (counts.sum() + NUM_CLASSES)).view(1, -1)

    class_bias = ckpt.get('class_bias', None)
    if class_bias is not None:
        class_bias = torch.as_tensor(class_bias, dtype=torch.float32, device=device)
        if class_bias.numel() != NUM_CLASSES:
            class_bias = None
        else:
            class_bias = class_bias.view(1, -1)

    preds = []
    with torch.inference_mode():
        for batch in dl:
            batch = batch.to(device, non_blocking=True)
            feats = extract_features(clip_model, batch)
            logits = head(feats).float()
            if logp is not None and tau != 0.0:
                logits = logits + tau * logp
            if class_bias is not None:
                logits = logits + class_bias
            preds.extend([int(x) for x in logits.argmax(dim=1).detach().cpu().tolist()])

    with open(args.output, 'w') as f:
        json.dump({'predictions': preds}, f)


if __name__ == '__main__':
    main()
